     7→import org.springframework.beans.factory.annotation.Value;
     8→import org.springframework.http.MediaType;
     9→import org.springframework.http.HttpStatus;
    10→import org.springframework.web.bind.annotation.*;
    11→import org.springframework.web.servlet.mvc.method.annotation.SseEmitter;
    12→
    13→import java.io.IOException;
    14→import java.util.HashMap;
    15→import java.util.List;
    16→import java.util.Map;
    17→
    18→@RestController
    19→@RequestMapping("/api/conversations")
    20→public class ConversationController {
    21→
    22→    private static final ObjectMapper OBJECT_MAPPER = new ObjectMapper();
    23→    /** 0L = no timeout (used when manual-approve is on so tool approval can wait indefinitely). */
    24→    private static final long NO_TIMEOUT = 0L;
    25→    private static final long DEFAULT_TIMEOUT_MS = 300_000L;
    26→
    27→    private final ConversationService conversationService;
    28→    private final boolean manualApprove;
    29→
    30→    public ConversationController(ConversationService conversationService,
    31→                                  @Value("${aidaemon.manual-approve:false}") boolean manualApprove) {
    32→        this.conversationService = conversationService;
    33→        this.manualApprove = manualApprove;
    34→    }
    35→
    36→    @PostMapping
    37→    @ResponseStatus(HttpStatus.CREATED)
    38→    public Map<String, Object> create(@RequestBody Map<String, String> request) {
    39→        var name = request.getOrDefault("name", "Untitled");
    40→        var providerId = request.get("providerId");
    41→        if (providerId != null && providerId.isBlank()) providerId = null;
    42→        var botName = request.get("botName");
    43→        if (botName != null && (botName.isBlank() || "default".equalsIgnoreCase(botName))) botName = null;
    44→        var conversation = conversationService.create(name, providerId, botName, null);
    45→        var out = new HashMap<String, Object>();
    46→        out.put("conversationId", conversation.id());
    47→        out.put("name", conversation.name());
    48→        out.put("providerId", conversation.providerId());
    49→        out.put("botName", conversation.botName());
    50→        return out;
    51→    }
    52→
    53→    @PatchMapping("/{id}")
    54→    public Conversation update(@PathVariable String id, @RequestBody Map<String, String> request) {
    55→        var conversation = conversationService.get(id);
    56→        var providerId = conversation.providerId();
    57→        if (request.containsKey("providerId")) {
    58→            var rawProviderId = request.get("providerId");
    59→            providerId = (rawProviderId == null || rawProviderId.isBlank()) ? null : rawProviderId;
    60→        }
    61→        var botName = conversation.botName();
    62→        if (request.containsKey("botName")) {
    63→            var rawBot = request.get("botName");
    64→            if (rawBot == null || rawBot.isBlank() || "default".equalsIgnoreCase(rawBot)) {
    65→                botName = null;
    66→            } else {
    67→                botName = rawBot;
    68→            }
    69→        }
    70→        var updated = new com.programmersdiary.aidaemon.chat.Conversation(
    71→                conversation.id(),
    72→                conversation.name(),
    73→                providerId,
    74→                botName,
    75→                conversation.messages(),
    76→                conversation.parentConversationId(),
    77→                conversation.createdAtMillis(),
    78→                conversation.participant1(),
    79→                conversation.participant2(),
    80→                conversation.direct());
    81→        conversationService.save(updated);
    82→        return updated;
    83→    }
    84→
    85→    @PostMapping("/{id}/messages")
    86→    public Map<String, String> sendMessage(@PathVariable String id, @RequestBody Map<String, String> request) {
    87→        var response = conversationService.sendMessage(id, request.get("message"));
    88→        return Map.of("response", response);
    89→    }
    90→
    91→    @PostMapping(value = "/{id}/messages/stream", produces = MediaType.TEXT_EVENT_STREAM_VALUE)
    92→    public SseEmitter sendMessageStream(@PathVariable String id, @RequestBody Map<String, String> request) {
    93→        var emitter = new SseEmitter(manualApprove ? NO_TIMEOUT : DEFAULT_TIMEOUT_MS);
    94→        conversationService.sendMessageStream(id, request.get("message"))
    95→                .subscribe(
    96→                        chunk -> {
    97→                            try {
    98→                                emitter.send(SseEmitter.event().data(OBJECT_MAPPER.writeValueAsString(chunk)));
    99→                            } catch (IOException e) {
   100→                                emitter.completeWithError(e);
   101→                            }
   102→                        },
   103→                        emitter::completeWithError,
   104→                        emitter::complete
   105→                );
   106→        return emitter;
   107→    }
   108→
   109→    @GetMapping
   110→    public List<Conversation> list(@RequestParam(required = false) String participant) {
   111→        if (participant != null && !participant.isBlank()) {
   112→            return conversationService.listForParticipant(participant);
   113→        }
   114→        return conversationService.listAll();
   115→    }
   116→
   117→    @DeleteMapping("/{id}")
   118→    @ResponseStatus(HttpStatus.NO_CONTENT)
   119→    public void delete(@PathVariable String id) {
   120→        conversationService.delete(id);
   121→    }
   122→
   123→    @GetMapping("/{id}")
   124→    public Conversation get(@PathVariable String id) {
   125→        return conversationService.get(id);
   126→    }
   127→
   128→    private static final String DEFAULT_USER_PARTICIPANT = "user";
   129→
   130→    @GetMapping("/direct/{botName}")
   131→    public Conversation getOrCreateDirect(@PathVariable String botName,
   132→                                         @RequestParam(required = false) String providerId) {
   133→        return conversationService.getOrCreateDirect(DEFAULT_USER_PARTICIPANT, botName, providerId);
   134→    }
   135→}
