    13→@Service
    14→public class ConversationService {
    15→
    16→    private final ConversationRepository conversationRepository;
    17→    private final ObjectProvider<DelegationService> delegationServiceProvider;
    18→    private final BotService botService;
    19→
    20→    public ConversationService(ConversationRepository conversationRepository,
    21→                               ObjectProvider<DelegationService> delegationServiceProvider,
    22→                               BotService botService) {
    23→        this.conversationRepository = conversationRepository;
    24→        this.delegationServiceProvider = delegationServiceProvider;
    25→        this.botService = botService;
    26→    }
    27→
    28→    public Conversation create(String name, String providerId) {
    29→        return create(name, providerId, null, null);
    30→    }
    31→
    32→    public Conversation create(String name, String providerId, String parentConversationId) {
    33→        return create(name, providerId, null, parentConversationId);
    34→    }
    35→
    36→    public Conversation create(String name, String providerId, String botName, String parentConversationId) {
    37→        var conversation = new Conversation(
    38→                UUID.randomUUID().toString(), name, providerId, botName, new ArrayList<>(), parentConversationId,
    39→                System.currentTimeMillis(), null, null, null);
    40→        return conversationRepository.save(conversation);
    41→    }
    42→
    43→    public String sendMessageBotToBot(String callerBotName, String targetBotName, String message, String providerId) {
    44→        if (callerBotName == null || callerBotName.isBlank() || "default".equalsIgnoreCase(callerBotName)) {
    45→            throw new IllegalArgumentException("Bot-to-bot messaging requires a named caller bot");
    46→        }
    47→        if (targetBotName == null || targetBotName.isBlank() || "default".equalsIgnoreCase(targetBotName)) {
    48→            throw new IllegalArgumentException("Target bot name is required");
    49→        }
    50→        if (callerBotName.equals(targetBotName)) {
    51→            throw new IllegalArgumentException("Caller and target bot must be different");
    52→        }
    53→        var botNames = botService.listBots().stream().map(b -> b.name()).toList();
    54→        if (!botNames.contains(callerBotName)) {
    55→            throw new IllegalArgumentException("Caller bot not found: " + callerBotName);
    56→        }
    57→        if (!botNames.contains(targetBotName)) {
    58→            throw new IllegalArgumentException("Target bot not found: " + targetBotName);
    59→        }
    60→        var conv = getOrCreateDirect(callerBotName, targetBotName, providerId);
    61→        return sendMessage(conv.id(), message);
    62→    }
    63→
    64→    public Conversation getOrCreateDirect(String userParticipantId, String botName, String providerId) {
    65→        if (botName == null || botName.isBlank() || "default".equalsIgnoreCase(botName)) {
    66→            throw new IllegalArgumentException("Direct chat requires a named bot");
    67→        }
    68→        if (!botService.listBots().stream().anyMatch(b -> botName.equals(b.name()))) {
    69→            throw new IllegalArgumentException("Bot not found: " + botName);
    70→        }
    71→        if (!"user".equals(userParticipantId) && !botService.listBots().stream().anyMatch(b -> userParticipantId.equals(b.name()))) {
    72→            throw new IllegalArgumentException("Participant not found: " + userParticipantId);
    73→        }
    74→        var id = Conversation.canonicalId(userParticipantId, botName);
    75→        var p1 = userParticipantId.compareTo(botName) <= 0 ? userParticipantId : botName;
    76→        var p2 = userParticipantId.compareTo(botName) <= 0 ? botName : userParticipantId;
    77→        return conversationRepository.findById(id)
    78→                .map(conv -> {
    79→                    if (providerId != null && !providerId.isBlank() && !providerId.equals(conv.providerId())) {
    80→                        var updated = new Conversation(conv.id(), conv.name(), providerId, conv.botName(),
    81→                                conv.messages(), conv.parentConversationId(), conv.createdAtMillis(),
    82→                                conv.participant1(), conv.participant2(), conv.direct());
    83→                        conversationRepository.save(updated);
    84→                        return updated;
    85→                    }
    86→                    return conv;
    87→                })
    88→                .orElseGet(() -> {
    89→                    var name = userParticipantId + " & " + botName;
    90→                    var conv = new Conversation(id, name, providerId, botName, new ArrayList<>(), null,
    91→                            System.currentTimeMillis(), p1, p2, true);
    92→                    return conversationRepository.save(conv);
    93→                });
    94→    }
    95→
    96→    public Conversation updateProvider(String conversationId, String providerId) {
    97→        var conversation = conversationRepository.findById(conversationId)
    98→                .orElseThrow(() -> new IllegalArgumentException("Conversation not found: " + conversationId));
    99→        var updated = new Conversation(conversation.id(), conversation.name(), providerId, conversation.botName(),
   100→                conversation.messages(), conversation.parentConversationId(), conversation.createdAtMillis(),
   101→                conversation.participant1(), conversation.participant2(), conversation.direct());
   102→        return conversationRepository.save(updated);
   103→    }
   104→
   105→    public void save(Conversation conversation) {
   106→        conversationRepository.save(conversation);
   107→    }
   108→
   109→    public String sendMessage(String conversationId, String userMessage) {
   110→        var conversation = conversationRepository.findById(conversationId)
   111→                .orElseThrow(() -> new IllegalArgumentException("Conversation not found: " + conversationId));
   112→        if (conversation.providerId() == null || conversation.providerId().isBlank()) {
   113→            throw new IllegalArgumentException("No agent selected for this conversation");
   114→        }
   115→        conversation.messages().add(ChatMessage.of("user", userMessage));
   116→        var bot = botService.getBot(conversation.botName());
   117→        var senderIdentity = senderIdentity(conversation);
   118→        var result = bot.chat(conversation.providerId(), conversation.messages(), conversationId, senderIdentity);
   119→        conversation.messages().add(ChatMessage.of("assistant", result.assistantContent()));
   120→        conversationRepository.save(conversation);
   121→
   122→        if (!result.pendingSubConversationIds().isEmpty()) {
   123→            var delegationService = delegationServiceProvider.getIfAvailable();
   124→            if (delegationService != null) {
   125→                delegationService.startSubAgents(result.pendingSubConversationIds());
   126→            }
   127→        }
   128→
   129→        return result.response();
   130→    }
   131→
   132→    public Flux<StreamChunk> sendMessageStream(String conversationId, String userMessage) {
   133→        var conversation = conversationRepository.findById(conversationId)
   134→                .orElseThrow(() -> new IllegalArgumentException("Conversation not found: " + conversationId));
   135→        if (conversation.providerId() == null || conversation.providerId().isBlank()) {
   136→            return Flux.error(new IllegalArgumentException("No agent selected for this conversation"));
   137→        }
   138→        conversation.messages().add(ChatMessage.of("user", userMessage));
   139→        conversationRepository.save(conversation);
   140→
   141→        var bot = botService.getBot(conversation.botName());
   142→        var senderIdentity = senderIdentity(conversation);
   143→        return bot.chatStream(conversation.providerId(), conversation.messages(), conversationId, result -> {
   144→            conversation.messages().add(ChatMessage.of("assistant", result.assistantContent()));
   145→            conversationRepository.save(conversation);
   146→            if (!result.pendingSubConversationIds().isEmpty()) {
   147→                var delegationService = delegationServiceProvider.getIfAvailable();
   148→                if (delegationService != null) {
   149→                    delegationService.startSubAgents(result.pendingSubConversationIds());
   150→                }
   151→            }
   152→        }, senderIdentity);
   153→    }
   154→
   155→    private static String senderIdentity(Conversation conversation) {
   156→        if (!conversation.isDirect() || conversation.botName() == null) return null;
   157→        var p1 = conversation.participant1();
   158→        var p2 = conversation.participant2();
   159→        if (p1 == null || p2 == null) return null;
   160→        var other = p1.equals(conversation.botName()) ? p2 : p1;
   161→        return "user".equalsIgnoreCase(other) ? null : other;
   162→    }
   163→
   164→    public Conversation get(String conversationId) {
   165→        return conversationRepository.findById(conversationId)
   166→                .orElseThrow(() -> new IllegalArgumentException("Conversation not found: " + conversationId));
   167→    }
   168→
   169→    public List<Conversation> listAll() {
   170→        return conversationRepository.findAll();
   171→    }
   172→
   173→    public List<Conversation> listForParticipant(String participantId) {
   174→        return conversationRepository.findAllForParticipant(participantId);
   175→    }
   176→
   177→    public void delete(String conversationId) {
   178→        conversationRepository.deleteById(conversationId);
   179→    }
   180→}
