     7→public record Conversation(String id,
     8→                           String name,
     9→                           String providerId,
    10→                           String botName,
    11→                           List<ChatMessage> messages,
    12→                           String parentConversationId,
    13→                           Long createdAtMillis,
    14→                           String participant1,
    15→                           String participant2,
    16→                           Boolean direct) {
    17→
    18→    public Conversation(String id, String name, String providerId, List<ChatMessage> messages, String parentConversationId) {
    19→        this(id, name, providerId, null, messages, parentConversationId, null, null, null, null);
    20→    }
    21→
    22→    public Conversation(String id, String name, String providerId, String botName, List<ChatMessage> messages,
    23→                        String parentConversationId, Long createdAtMillis) {
    24→        this(id, name, providerId, botName, messages, parentConversationId, createdAtMillis, null, null, null);
    25→    }
    26→
    27→    public static String canonicalId(String a, String b) {
    28→        if (a == null || b == null) return null;
    29→        return a.compareTo(b) <= 0 ? a + "_" + b : b + "_" + a;
    30→    }
    31→
    32→    @JsonIgnore
    33→    public boolean isDirect() {
    34→        return Boolean.TRUE.equals(direct) || (participant1 != null && participant2 != null);
    35→    }
    36→}
