    37→    const p1 = conversation.participant1 ?? '';
    38→    const p2 = conversation.participant2 ?? '';
    39→    const bot = conversation.botName ?? '';
    40→    if (p1 && p2 && bot && p1 !== 'user' && p2 !== 'user') {
    41→      return p1 === bot ? p2 : p1;
    42→    }
    43→    return 'user';
    44→  }
    45→  if (role === 'assistant') {
    46→    const bot = conversation.botName ?? '';
    47→    if (bot) return bot;
    48→    const p1 = conversation.participant1 ?? '';
    49→    const p2 = conversation.participant2 ?? '';
    50→    if (p1 && p2) return p1 === 'user' ? p2 : p2 === 'user' ? p1 : p2;
    51→  }
    52→  return role;
