   293→  inputDraft,
   294→  onInputDraftChange,
   295→  onSend,
   296→  onUpdateProvider,
   297→  onUpdateBot,
   298→  pendingApprovals,
   299→  onApproveTool,
   300→  onRejectTool,
   301→}: ChatWindowProps) {
   302→  const [hideToolsAndThinking, setHideToolsAndThinking] = useState(false);
   303→  const [isRecording, setIsRecording] = useState(false);
   304→  const [speakingIdx, setSpeakingIdx] = useState<number | null>(null);
   305→  const messagesRef = useRef<HTMLDivElement>(null);
   306→  const topRef = useRef<HTMLDivElement>(null);
   307→  const bottomRef = useRef<HTMLDivElement>(null);
   308→  const recognitionRef = useRef<any>(null);
   309→
   310→  // Stop recording and TTS when conversation changes
   311→  useEffect(() => {
   312→    recognitionRef.current?.stop();
   313→    setIsRecording(false);
   314→    speechSynthesis.cancel();
   315→    setSpeakingIdx(null);
   316→  }, [conversation?.id]);
   317→
   318→  const visibleMessages = conversation
   319→    ? getDisplayMessages(conversation.messages, hideToolsAndThinking, lastStreamedContent)
   320→    : [];
   321→
   322→  useEffect(() => {
   323→    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
   324→  }, [conversation?.messages.length, streaming?.reasoning, streaming?.parts?.length]);
   325→
   326→  const hasProvider = Boolean(conversation?.providerId);
   327→  const isDirectChat = Boolean(
   328→    conversation?.participant1 != null && conversation?.participant2 != null
   329→  );
   330→
   331→  const handleSend = () => {
   332→    const trimmed = inputDraft.trim();
   333→    if (!trimmed || sending || !hasProvider) return;
   334→    onSend(trimmed);
   335→  };
   336→
   337→  const scrollToTop = () => topRef.current?.scrollIntoView({ behavior: 'smooth' });
   338→  const scrollToBottom = () => bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
   339→
   340→  const toggleRecording = () => {
   341→    if (isRecording) {
   342→      recognitionRef.current?.stop();
   343→      setIsRecording(false);
   344→      return;
   345→    }
   346→    const SpeechRecognitionAPI =
   347→      (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
   348→    if (!SpeechRecognitionAPI) {
   349→      alert('Speech recognition is not supported in this browser. Try Chrome or Edge.');
   350→      return;
   351→    }
   352→    const recognition = new SpeechRecognitionAPI();
   353→    recognition.continuous = true;
   354→    recognition.interimResults = true;
   355→    recognition.lang = 'en-US';
   356→    // Capture the base text at recording start; all mutations use this as ground truth
   357→    const startBase = inputDraft;
   358→    let committedText = startBase;
   359→    recognition.onresult = (event: any) => {
   360→      let interim = '';
   361→      for (let i = event.resultIndex; i < event.results.length; i++) {
   362→        const t = event.results[i][0].transcript;
   363→        if (event.results[i].isFinal) {
   364→          committedText += (committedText && !committedText.endsWith(' ') ? ' ' : '') + t.trim();
   365→        } else {
   366→          interim = t;
   367→        }
   368→      }
   369→      if (interim) {
   370→        onInputDraftChange(committedText + (committedText && !committedText.endsWith(' ') ? ' ' : '') + interim + ' […]');
   371→      } else {
   372→        onInputDraftChange(committedText);
   373→      }
   374→    };
   375→    recognition.onend = () => {
   376→      setIsRecording(false);
   377→      onInputDraftChange(committedText);
   378→    };
   379→    recognition.onerror = () => {
   380→      setIsRecording(false);
   381→      onInputDraftChange(committedText);
   382→    };
   383→    recognitionRef.current = recognition;
   384→    recognition.start();
   385→    setIsRecording(true);
   386→  };
   387→
   388→  const speakMessage = (msg: DisplayMessage, idx: number) => {
   389→    if (speakingIdx === idx) {
   390→      speechSynthesis.cancel();
   391→      setSpeakingIdx(null);
   392→      return;
   393→    }
   394→    const text = getMessagePlainText(msg, !hideToolsAndThinking);
   395→    if (!text.trim()) return;
   396→    speechSynthesis.cancel();
   397→    const utterance = new SpeechSynthesisUtterance(text);
   398→    utterance.onend = () => setSpeakingIdx(null);
   399→    utterance.onerror = () => setSpeakingIdx(null);
   400→    setSpeakingIdx(idx);
   401→    speechSynthesis.speak(utterance);
   402→  };
