     1→import { useEffect, useRef, useState } from 'react';
     2→import Sidebar from './components/Sidebar';
     3→import ChatWindow from './components/ChatWindow';
     4→import * as api from './api';
     5→import type { Bot, Conversation, CreateBotRequest, CreateProviderRequest, PendingToolApproval, Provider } from './types';
     6→
     7→export interface StreamPart {
     8→  type: 'answer' | 'tool' | 'reasoning';
     9→  content: string;
    10→}
    11→
    12→export interface StreamingContent {
    13→  reasoning: string;
    14→  parts: StreamPart[];
    15→}
    16→
    17→export default function App() {
    18→  const [providers, setProviders] = useState<Provider[]>([]);
    19→  const [bots, setBots] = useState<Bot[]>([]);
    20→  const [conversations, setConversations] = useState<Conversation[]>([]);
    21→  const [activeId, setActiveId] = useState<string | null>(null);
    22→  const [selectedBot, setSelectedBot] = useState<string | null>(null);
    23→  const [sending, setSending] = useState(false);
    24→  const [streaming, setStreaming] = useState<StreamingContent | null>(null);
    25→  const [pendingApprovals, setPendingApprovals] = useState<PendingToolApproval[]>([]);
    26→  const [lastStreamedContent, setLastStreamedContent] = useState<{ conversationId: string; reasoning: string; parts: StreamPart[] } | null>(null);
    27→  const [, setDraftVersion] = useState(0);
    28→  const inputDraftRef = useRef('');
    29→  const streamingRef = useRef<StreamingContent | null>(null);
    30→  const pollIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
    31→  const activeIdRef = useRef(activeId);
    32→  const selectedBotRef = useRef(selectedBot);
    33→  activeIdRef.current = activeId;
    34→  selectedBotRef.current = selectedBot;
    35→
    36→  const setInputDraft = (value: string) => {
    37→    inputDraftRef.current = value;
    38→    setDraftVersion((v) => v + 1);
    39→  };
    40→
    41→  useEffect(() => {
    42→    api.fetchProviders().then(setProviders);
    43→    api.fetchBots().then(setBots);
    44→  }, []);
    45→
    46→  useEffect(() => {
    47→    const participant = selectedBot ?? 'user';
    48→    api.fetchConversations(participant).then(setConversations);
    49→  }, [selectedBot]);
    50→
    51→  useEffect(() => {
    52→    return () => {
    53→      if (pollIntervalRef.current) clearInterval(pollIntervalRef.current);
    54→    };
    55→  }, []);
    56→
    57→  const activeConversation = conversations.find((c) => c.id === activeId) ?? null;
    58→  const displayConversations =
    59→    selectedBot != null
    60→      ? conversations
    61→      : conversations.filter((c) => !(c.participant1 != null && c.participant2 != null));
    62→  const headerTitle = selectedBot ?? 'User';
    63→
    64→  useEffect(() => {
    65→    if (activeId != null && !displayConversations.some((c) => c.id === activeId)) {
    66→      setActiveId(null);
    67→    }
    68→  }, [selectedBot, activeId, displayConversations]);
    69→
    70→  const handleAddProvider = async (req: CreateProviderRequest) => {
    71→    const created = await api.createProvider(req);
    72→    setProviders((prev) => [...prev, created]);
    73→  };
    74→
    75→  const handleAddBot = async (req: CreateBotRequest) => {
    76→    const created = await api.createBot(req);
    77→    setBots((prev) => [...prev, created]);
    78→  };
    79→
    80→  const handleCreateConversation = async (name: string, providerId?: string | null) => {
    81→    const res = await api.createConversation(name, providerId);
    82→    const conv: Conversation = {
    83→      id: res.conversationId,
    84→      name: res.name,
    85→      providerId: res.providerId ?? null,
    86→      botName: res.botName ?? null,
    87→      messages: [],
    88→    };
    89→    setConversations((prev) => [...prev, conv]);
    90→    setActiveId(conv.id);
    91→  };
    92→
    93→  const handleOpenDirectChat = async (botName: string, providerId?: string | null) => {
    94→    const conv = await api.getOrCreateDirectConversation(botName, providerId);
    95→    setConversations((prev) => {
    96→      const exists = prev.some((c) => c.id === conv.id);
    97→      if (exists) return prev.map((c) => (c.id === conv.id ? conv : c));
    98→      return [...prev, conv];
    99→    });
   100→    setActiveId(conv.id);
   101→  };
   102→
   103→  const handleNewConversationWithBot = async (botName: string) => {
   104→    setSelectedBot(botName);
   105→    await handleOpenDirectChat(botName);
   106→  };
   107→
   108→  const handleUpdateConversationProvider = async (id: string, providerId: string | null) => {
   109→    const updated = await api.updateConversation(id, { providerId });
   110→    setConversations((prev) =>
   111→      prev.map((c) => (c.id === id ? { ...c, providerId: updated.providerId ?? null } : c)),
   112→    );
   113→  };
   114→
   115→  const handleUpdateConversationBot = async (id: string, botName: string | null) => {
   116→    const updated = await api.updateConversation(id, { botName });
   117→    setConversations((prev) =>
   118→      prev.map((c) => (c.id === id ? { ...c, botName: updated.botName ?? null } : c)),
   119→    );
   120→  };
   121→
   122→  const handleDeleteConversation = async (id: string) => {
   123→    await api.deleteConversation(id);
   124→    setConversations((prev) => prev.filter((c) => c.id !== id));
   125→    if (activeId === id) setActiveId(null);
   126→  };
   127→
   128→  const handleSend = async (message: string) => {
   129→    if (!activeId) return;
   130→    inputDraftRef.current = '';
   131→    setDraftVersion((v) => v + 1);
   132→    if (pollIntervalRef.current) {
   133→      clearInterval(pollIntervalRef.current);
   134→      pollIntervalRef.current = null;
   135→    }
   136→    setLastStreamedContent(null);
   137→    setConversations((prev) =>
   138→      prev.map((c) =>
   139→        c.id === activeId
   140→          ? { ...c, messages: [...c.messages, { role: 'user', content: message, timestampMillis: Date.now() }] }
   141→          : c,
   142→      ),
   143→    );
   144→    setSending(true);
   145→    const initial: StreamingContent = { reasoning: '', parts: [] };
   146→    setStreaming(initial);
   147→    streamingRef.current = initial;
   148→    api.sendMessageStream(
   149→      activeId,
   150→      message,
   151→      (chunk) => {
   152→        if (chunk.type === 'tool_pending') {
   153→          try {
   154→            const approval = JSON.parse(chunk.content) as PendingToolApproval;
   155→            setPendingApprovals((prev) => [...prev, approval]);
   156→          } catch {
   157→            // skip malformed chunk
   158→          }
   159→          return;
   160→        }
   161→        if (chunk.type === 'tool') {
   162→          // Tool finished (approved or rejected) — remove matching pending approval
   163→          setPendingApprovals((prev) => {
   164→            if (prev.length === 0) return prev;
   165→            // Remove the first pending entry whose toolName appears in the tool chunk content
   166→            const idx = prev.findIndex((p) => chunk.content.includes(p.toolName));
   167→            if (idx === -1) return prev;
   168→            return [...prev.slice(0, idx), ...prev.slice(idx + 1)];
   169→          });
   170→        }
   171→        setStreaming((prev) => {
   172→          if (!prev) return prev;
   173→          let next: StreamingContent;
   174→          if (chunk.type === 'reasoning') {
   175→            next = { ...prev, reasoning: prev.reasoning + chunk.content };
   176→          } else if (chunk.type === 'tool') {
   177→            next = { ...prev, parts: [...prev.parts, { type: 'tool', content: chunk.content }] };
   178→          } else {
   179→            const prevParts = prev.parts;
   180→            const last = prevParts[prevParts.length - 1];
   181→            if (last?.type === 'answer') {
   182→              next = {
   183→                ...prev,
   184→                parts: [...prevParts.slice(0, -1), { type: 'answer', content: last.content + chunk.content }],
   185→              };
   186→            } else {
   187→              next = { ...prev, parts: [...prevParts, { type: 'answer', content: chunk.content }] };
   188→            }
   189→          }
   190→          streamingRef.current = next;
   191→          return next;
   192→        });
   193→      },
   194→      () => {
   195→        const ref = streamingRef.current;
   196→        if (activeId && ref && (ref.reasoning || ref.parts.length > 0)) {
   197→          setLastStreamedContent({ conversationId: activeId, reasoning: ref.reasoning ?? '', parts: ref.parts });
   198→        }
   199→        setSending(false);
   200→        setStreaming(null);
   201→        streamingRef.current = null;
   202→        setPendingApprovals([]);
   203→        const participant = selectedBotRef.current ?? 'user';
   204→        const poll = () => {
   205→          api.fetchConversations(participant).then((list) => setConversations([...list]));
   206→        };
   207→        poll();
   208→        pollIntervalRef.current = setInterval(poll, 2500);
   209→        setTimeout(() => {
   210→          if (pollIntervalRef.current) {
   211→            clearInterval(pollIntervalRef.current);
   212→            pollIntervalRef.current = null;
   213→          }
   214→        }, 60000);
   215→      },
   216→      () => {
   217→        setSending(false);
   218→        setStreaming(null);
   219→        streamingRef.current = null;
   220→        setPendingApprovals([]);
   221→        api.fetchConversations(selectedBotRef.current ?? 'user').then(setConversations);
   222→      }
   223→    );
   224→  };
   225→
   226→  const handleApproveTool = async (approvalId: string) => {
   227→    setPendingApprovals((prev) => prev.filter((p) => p.approvalId !== approvalId));
   228→    await api.approveTool(approvalId);
   229→  };
   230→
   231→  const handleRejectTool = async (approvalId: string) => {
   232→    setPendingApprovals((prev) => prev.filter((p) => p.approvalId !== approvalId));
   233→    await api.rejectTool(approvalId);
   234→  };
   235→
   236→  return (
   237→    <div className="flex h-screen">
   238→      <Sidebar
   239→        providers={providers}
   240→        bots={bots}
   241→        conversations={displayConversations}
   242→        activeId={activeId}
   243→        selectedBot={selectedBot}
   244→        onSelectBot={setSelectedBot}
   245→        onSelectConversation={setActiveId}
   246→        onCreateConversation={handleCreateConversation}
   247→        onNewConversationWithBot={handleNewConversationWithBot}
   248→        onDeleteConversation={handleDeleteConversation}
   249→        onAddProvider={handleAddProvider}
   250→        onAddBot={handleAddBot}
   251→      />
   252→      <ChatWindow
   253→        key={activeId ?? ''}
   254→        headerTitle={headerTitle}
   255→        conversation={activeConversation}
   256→        providers={providers}
   257→        bots={bots}
   258→        sending={sending}
   259→        streaming={streaming}
   260→        lastStreamedContent={activeId && lastStreamedContent?.conversationId === activeId ? lastStreamedContent : null}
   261→        inputDraft={inputDraftRef.current}
   262→        onInputDraftChange={setInputDraft}
   263→        onSend={handleSend}
   264→        onUpdateProvider={handleUpdateConversationProvider}
   265→        onUpdateBot={handleUpdateConversationBot}
   266→        pendingApprovals={pendingApprovals}
   267→        onApproveTool={handleApproveTool}
   268→        onRejectTool={handleRejectTool}
   269→      />
   270→    </div>
   271→  );
   272→}
