     1→package com.programmersdiary.aidaemon.chat;
     2→
     3→import com.fasterxml.jackson.core.JsonProcessingException;
     4→import com.fasterxml.jackson.databind.ObjectMapper;
     5→import com.programmersdiary.aidaemon.bot.BotService;
     6→import com.programmersdiary.aidaemon.bot.PersonalMemoryEntry;
     7→import com.programmersdiary.aidaemon.skills.SkillsService;
     8→import org.springframework.ai.chat.messages.AssistantMessage;
     9→import org.springframework.ai.chat.messages.Message;
    10→import org.springframework.ai.chat.messages.SystemMessage;
    11→import org.springframework.ai.chat.messages.UserMessage;
    12→
    13→import java.util.ArrayList;
    14→import java.util.List;
    15→import java.util.Map;
    16→
    17→public class ChatContextBuilder {
    18→
    19→    private static final List<String> REASONING_KEYS =
    20→            List.of("thinking", "reasoningContent", "reasoning_content", "reasoning");
    21→
    22→    private final BotService botService;
    23→    private final SkillsService skillsService;
    24→    private final ObjectMapper objectMapper;
    25→
    26→    public ChatContextBuilder(BotService botService, SkillsService skillsService) {
    27→        this.botService = botService;
    28→        this.skillsService = skillsService;
    29→        this.objectMapper = new ObjectMapper();
    30→    }
    31→
    32→    public List<Message> buildMessages(List<ChatMessage> messages, String botName,
    33→                                      int conversationLimit, int personalMemoryLimit, String systemInstructions,
    34→                                      String senderIdentity) {
    35→        var springMessages = new ArrayList<Message>();
    36→        springMessages.add(SystemMessage.builder().text(systemInstructions != null ? systemInstructions : "").metadata(cacheControl()).build());
    37→        var soul = botService.loadSoul(botName);
    38→        if (soul != null && !soul.isBlank()) {
    39→            springMessages.add(new SystemMessage(soul));
    40→        }
    41→        if (senderIdentity != null && !senderIdentity.isBlank() && !"user".equalsIgnoreCase(senderIdentity)) {
    42→            springMessages.add(new SystemMessage(
    43→                    "The message is from bot named \"" + senderIdentity + "\"."));
    44→        }
    45→        if (personalMemoryLimit > 0) {
    46→            var trimmed = botService.loadPersonalMemoryTrimmed(botName, personalMemoryLimit);
    47→            if (!trimmed.entries().isEmpty()) {
    48→                springMessages.add(new SystemMessage(
    49→                        "Personal memory (recent interactions across conversations). "
    50→                                + trimmed.totalEntryCount() + " messages in total. Current context: message index "
    51→                                + trimmed.startIndexInclusive() + " (inclusive) to latest. Use retrieve_older_messages for conversation history; use retrieve_older_personal_memory for older personal memory."));
    52→                springMessages.addAll(personalMemoryToMessages(trimmed.entries()));
    53→            }
    54→        }
    55→        springMessages.addAll(memoryMessages());
    56→        var filtered = messages.stream().filter(m -> !"tool".equals(m.role())).toList();
    57→        var history = filtered.subList(0, filtered.size() - 1);
    58→        if (!history.isEmpty()) {
    59→            var trimmed = ContextWindowTrimmer.trimChatHistory(history, conversationLimit);
    60→            int firstInContext = history.size() - trimmed.size();
    61→            springMessages.add(new SystemMessage(
    62→                    "This conversation has " + filtered.size() + " messages. "
    63→                            + "Your current context includes messages from index " + firstInContext + " (inclusive) to the latest. "
    64→                            + "Use retrieve_older_messages tool to fetch earlier messages if needed."));
    65→            springMessages.addAll(conversationHistory(trimmed));
    66→        }
    67→        springMessages.add(toNotCachedSpringMessage(filtered.get(filtered.size() - 1)));
    68→        return springMessages;
    69→    }
    70→
    71→    private List<Message> memoryMessages() {
    72→        var memory = skillsService.readMemory().entrySet().stream().toList();
    73→        var result = new ArrayList<Message>();
    74→        memory.subList(0, memory.size() - 1)
    75→                .forEach(e -> result.add(new SystemMessage(e.getKey() + ": " + e.getValue())));
    76→        result.add(SystemMessage.builder()
    77→                .text(memory.get(memory.size() - 1).getKey() + ": " + memory.get(memory.size() - 1).getValue())
    78→                .metadata(cacheControl())
    79→                .build());
    80→        return result;
    81→    }
    82→
    83→    private List<Message> personalMemoryToMessages(List<PersonalMemoryEntry> entries) {
    84→        var result = new ArrayList<Message>();
    85→        for (int i = 0; i < entries.size(); i++) {
    86→            var e = entries.get(i);
    87→            var content = e.content() != null ? e.content() : "";
    88→            var isLast = i == entries.size() - 1;
    89→            switch (e.role().toLowerCase()) {
    90→                case "user" -> result.add(isLast
    91→                        ? UserMessage.builder().text(content).metadata(cacheControl()).build()
    92→                        : new UserMessage(content));
    93→                case "assistant" -> result.add(isLast
    94→                        ? AssistantMessage.builder().content(content).properties(cacheControl()).build()
    95→                        : new AssistantMessage(content));
    96→                default -> result.add(new SystemMessage("[Tool] " + content));
    97→            }
    98→        }
    99→        return result;
   100→    }
   101→
   102→    private List<Message> conversationHistory(List<ChatMessage> trimmedHistory) {
   103→        var result = new ArrayList<Message>();
   104→        if (!trimmedHistory.isEmpty()) {
   105→            trimmedHistory.forEach(m -> result.add(toNotCachedSpringMessage(m)));
   106→            result.add(toCachedSpringMessage(trimmedHistory.get(trimmedHistory.size() - 1)));
   107→        }
   108→        return result;
   109→    }
   110→
   111→    private Message toNotCachedSpringMessage(ChatMessage message) {
   112→        return switch (message.role()) {
   113→            case "system" -> new SystemMessage(message.content());
   114→            case "assistant" -> new AssistantMessage(flattenStructuredContent(message.content()));
   115→            default -> new UserMessage(message.content());
   116→        };
   117→    }
   118→
   119→    private Message toCachedSpringMessage(ChatMessage message) {
   120→        return switch (message.role()) {
   121→            case "system" -> SystemMessage.builder().text(message.content()).metadata(cacheControl()).build();
   122→            case "assistant" -> AssistantMessage.builder()
   123→                    .content(flattenStructuredContent(message.content()))
   124→                    .properties(cacheControl())
   125→                    .build();
   126→            default -> UserMessage.builder().text(message.content()).metadata(cacheControl()).build();
   127→        };
   128→    }
   129→
   130→    private String flattenStructuredContent(String content) {
   131→        if (content == null || !content.trim().startsWith("{\"parts\":")) {
   132→            return content != null ? content : "";
   133→        }
   134→        try {
   135→            @SuppressWarnings("unchecked")
   136→            var map = objectMapper.readValue(content, Map.class);
   137→            var parts = (List<?>) map.get("parts");
   138→            if (parts == null) return content;
   139→            var sb = new StringBuilder();
   140→            for (var o : parts) {
   141→                if (!(o instanceof Map<?, ?> p)) continue;
   142→                var type = p.get("type");
   143→                if (type != null && REASONING_KEYS.contains(type.toString())) continue;
   144→                var partContent = p.get("content");
   145→                if (partContent == null) continue;
   146→                var contentStr = partContent.toString();
   147→                if ("answer".equals(type)) {
   148→                    sb.append(contentStr);
   149→                } else {
   150→                    sb.append("\n[Tool]\n").append(contentStr).append("\n");
   151→                }
   152→            }
   153→            return sb.toString();
   154→        } catch (JsonProcessingException | ClassCastException e) {
   155→            return content;
   156→        }
   157→    }
   158→
   159→    private static Map<String, Object> cacheControl() {
   160→        return Map.of("cache_control", Map.of("type", "ephemeral"));
   161→    }
   162→}
