     2→
     3→import com.fasterxml.jackson.databind.ObjectMapper;
     4→import org.springframework.ai.chat.model.ToolContext;
     5→import org.springframework.ai.tool.ToolCallback;
     6→import org.springframework.ai.tool.definition.ToolDefinition;
     7→import org.springframework.ai.tool.metadata.ToolMetadata;
     8→
     9→import java.util.List;
    10→import java.util.Map;
    11→import java.util.UUID;
    12→import java.util.concurrent.CompletableFuture;
    13→import java.util.concurrent.ExecutionException;
    14→import java.util.concurrent.TimeUnit;
    15→import java.util.concurrent.TimeoutException;
    16→import java.util.function.Consumer;
    17→
    18→public class LoggingToolCallback implements ToolCallback {
    19→
    20→    private static final ObjectMapper JSON = new ObjectMapper();
    21→
    22→    private final ToolCallback delegate;
    23→    private final List<ChatMessage> toolLog;
    24→    private final String serverName;
    25→    private final Consumer<StreamChunk> onToolChunk;
    26→    private final ToolApprovalService approvalService;
    27→    /** Seconds to wait for tool execution after approval. 0 means no limit. */
    28→    private final int toolExecutionTimeoutSeconds;
    29→
    30→    public LoggingToolCallback(ToolCallback delegate, List<ChatMessage> toolLog) {
    31→        this(delegate, toolLog, null, null, null, 0);
    32→    }
    33→
    34→    public LoggingToolCallback(ToolCallback delegate, List<ChatMessage> toolLog, String serverName) {
    35→        this(delegate, toolLog, serverName, null, null, 0);
    36→    }
    37→
    38→    public LoggingToolCallback(ToolCallback delegate, List<ChatMessage> toolLog, String serverName,
    39→                               Consumer<StreamChunk> onToolChunk) {
    40→        this(delegate, toolLog, serverName, onToolChunk, null, 0);
    41→    }
    42→
    43→    public LoggingToolCallback(ToolCallback delegate, List<ChatMessage> toolLog, String serverName,
    44→                               Consumer<StreamChunk> onToolChunk, ToolApprovalService approvalService) {
    45→        this(delegate, toolLog, serverName, onToolChunk, approvalService, 0);
    46→    }
    47→
    48→    public LoggingToolCallback(ToolCallback delegate, List<ChatMessage> toolLog, String serverName,
    49→                               Consumer<StreamChunk> onToolChunk, ToolApprovalService approvalService,
    50→                               int toolExecutionTimeoutSeconds) {
    51→        this.delegate = delegate;
    52→        this.toolLog = toolLog;
    53→        this.serverName = serverName;
    54→        this.onToolChunk = onToolChunk;
    55→        this.approvalService = approvalService;
    56→        this.toolExecutionTimeoutSeconds = toolExecutionTimeoutSeconds;
    57→    }
    58→
    59→    @Override
    60→    public ToolDefinition getToolDefinition() {
    61→        var def = delegate.getToolDefinition();
    62→        if (serverName == null || serverName.isBlank()) {
    63→            return def;
    64→        }
    65→        var prefixed = serverName + "." + def.name();
    66→        return ToolDefinition.builder()
    67→                .name(sanitizeToolName(prefixed))
    68→                .description(def.description())
    69→                .inputSchema(def.inputSchema())
    70→                .build();
    71→    }
    72→
    73→    private static String sanitizeToolName(String name) {
    74→        return name.replaceAll("[^a-zA-Z0-9_-]", "_");
    75→    }
    76→
    77→    @Override
    78→    public ToolMetadata getToolMetadata() {
    79→        return delegate.getToolMetadata();
    80→    }
    81→
    82→    @Override
    83→    public String call(String toolInput) {
    84→        if (approvalService != null) {
    85→            var approved = requestApproval(toolInput);
    86→            if (!approved) return buildRejectionResult(toolInput);
    87→        }
    88→        var result = executeWithTimeout(() -> delegate.call(toolInput), toolInput);
    89→        log(toolInput, result);
    90→        return result;
    91→    }
    92→
    93→    @Override
    94→    public String call(String toolInput, ToolContext toolContext) {
    95→        if (approvalService != null) {
    96→            var approved = requestApproval(toolInput);
    97→            if (!approved) return buildRejectionResult(toolInput);
    98→        }
    99→        var result = executeWithTimeout(() -> delegate.call(toolInput, toolContext), toolInput);
   100→        log(toolInput, result);
   101→        return result;
   102→    }
   103→
   104→    private String executeWithTimeout(java.util.function.Supplier<String> execution, String toolInput) {
   105→        if (toolExecutionTimeoutSeconds <= 0) {
   106→            return execution.get();
   107→        }
   108→        var execFuture = CompletableFuture.supplyAsync(execution);
   109→        try {
   110→            return execFuture.get(toolExecutionTimeoutSeconds, TimeUnit.SECONDS);
   111→        } catch (TimeoutException e) {
   112→            execFuture.cancel(true);
   113→            return buildTimeoutResult(toolInput);
   114→        } catch (InterruptedException e) {
   115→            Thread.currentThread().interrupt();
   116→            return buildTimeoutResult(toolInput);
   117→        } catch (ExecutionException e) {
   118→            throw new RuntimeException(e.getCause());
   119→        }
   120→    }
   121→
   122→    private boolean requestApproval(String toolInput) {
   123→        var approvalId = UUID.randomUUID().toString();
   124→        var toolName = delegate.getToolDefinition().name();
   125→        var label = serverName != null ? serverName + " > " + toolName : toolName;
   126→        var pendingContent = buildPendingJson(approvalId, label, toolInput);
   127→        // Register the future BEFORE emitting the chunk so the consumer can approve/reject immediately
   128→        var future = approvalService.requestApproval(approvalId);
   129→        if (onToolChunk != null) {
   130→            onToolChunk.accept(new StreamChunk(StreamChunk.TYPE_TOOL_PENDING, pendingContent));
   131→        }
   132→        try {
   133→            return future.get();
   134→        } catch (InterruptedException e) {
   135→            Thread.currentThread().interrupt();
   136→            return false;
   137→        } catch (ExecutionException e) {
   138→            return false;
   139→        }
   140→    }
   141→
   142→    private String buildRejectionResult(String toolInput) {
   143→        var toolName = delegate.getToolDefinition().name();
   144→        var label = serverName != null ? serverName + " > " + toolName : toolName;
   145→        var content = "[" + label + "]\nInput: " + toolInput + "\nOutput: Tool call rejected by user.";
   146→        toolLog.add(ChatMessage.of("tool", content));
   147→        if (onToolChunk != null) {
   148→            onToolChunk.accept(new StreamChunk(StreamChunk.TYPE_TOOL, content));
   149→        }
   150→        return "Tool call was rejected by the user.";
   151→    }
   152→
   153→    private String buildTimeoutResult(String toolInput) {
   154→        var toolName = delegate.getToolDefinition().name();
   155→        var label = serverName != null ? serverName + " > " + toolName : toolName;
   156→        var content = "[" + label + "]\nInput: " + toolInput
   157→                + "\nOutput: Tool execution timed out after " + toolExecutionTimeoutSeconds + "s.";
   158→        toolLog.add(ChatMessage.of("tool", content));
   159→        if (onToolChunk != null) {
   160→            onToolChunk.accept(new StreamChunk(StreamChunk.TYPE_TOOL, content));
   161→        }
   162→        return "Tool execution timed out.";
   163→    }
   164→
   165→    private void log(String input, String output) {
   166→        var toolName = delegate.getToolDefinition().name();
   167→        var label = serverName != null ? serverName + " > " + toolName : toolName;
   168→        var content = "[" + label + "]\nInput: " + input + "\nOutput: " + output;
   169→        toolLog.add(ChatMessage.of("tool", content));
   170→        if (onToolChunk != null) {
   171→            onToolChunk.accept(new StreamChunk(StreamChunk.TYPE_TOOL, content));
   172→        }
   173→    }
   174→
   175→    private static String buildPendingJson(String approvalId, String toolName, String toolInput) {
   176→        try {
   177→            return JSON.writeValueAsString(Map.of(
   178→                    "approvalId", approvalId,
   179→                    "toolName", toolName,
   180→                    "toolInput", toolInput));
   181→        } catch (Exception e) {
   182→            return "{}";
   183→        }
   184→    }
   185→}
