   212→                      {part.content}
   213→                    </pre>
   214→                  </details>
   215→                ) : part.type === 'reasoning' ? (
   216→                  <details key={i} className="mb-2" open>
   217→                    <summary className="cursor-pointer text-text-dim text-xs font-semibold uppercase">
