   219→                    </summary>
   220→                    <pre className="mt-1.5 p-2 bg-bg rounded-lg text-xs text-text-dim whitespace-pre-wrap break-words max-h-[200px] overflow-y-auto">
   221→                      {part.content}
   222→                    </pre>
   223→                  </details>
   224→                ) : (
   225→                  <span key={i}>{part.content}</span>
