   234→
   235→function parseStructuredContent(content: string): StreamPart[] | null {
   236→  if (!content || typeof content !== 'string') return null;
   237→  const trimmed = content.trim();
   238→  if (!trimmed.startsWith('{"parts":')) return null;
   239→  try {
   240→    const data = JSON.parse(content) as { parts?: Array<{ type: string; content: string }> };
   241→    if (!Array.isArray(data.parts)) return null;
   242→    const parts: StreamPart[] = data.parts
   243→      .filter((p) => p && (p.type === 'answer' || p.type === 'tool' || p.type === 'reasoning') && typeof p.content === 'string')
   244→      .map((p) => ({ type: p.type as 'answer' | 'tool' | 'reasoning', content: p.content }));
   245→    return parts.length > 0 ? parts : null;
   246→  } catch {
   247→    return null;
   248→  }
   249→}
   250→
   251→function filterParts(parts: StreamPart[], hideToolsAndThinking: boolean): StreamPart[] {
   252→  if (!hideToolsAndThinking) return parts;
   253→  const answerParts = parts.filter((p) => p.type === 'answer');
   254→  return answerParts.map((p, i, arr) => ({
   255→    ...p,
   256→    content: p.content + (i < arr.length - 1 ? '\n\n' : ''),
   257→  }));
   258→}
   259→
   260→function getDisplayMessages(
   261→  messages: ChatMessage[],
   262→  hideToolsAndThinking: boolean,
   263→  lastStreamedContent: { reasoning: string; parts: StreamPart[] } | null
   264→): DisplayMessage[] {
   265→  let list: DisplayMessage[] = messages.map((msg) => {
   266→    if (msg.role === 'assistant') {
   267→      const parts = parseStructuredContent(msg.content);
   268→      if (parts) return { role: 'assistant' as const, parts: filterParts(parts, hideToolsAndThinking) };
   269→    }
   270→    return msg;
   271→  });
   272→  if (lastStreamedContent && list.length > 0) {
   273→    const lastUserIdx = Math.max(...list.map((msg, i) => (msg.role === 'user' ? i : -1)));
   274→    const afterLastUser = list.slice(lastUserIdx + 1);
   275→    if (afterLastUser.length === 1 && afterLastUser[0].role === 'assistant') {
   276→      const parts: StreamPart[] = lastStreamedContent.reasoning
   277→        ? [{ type: 'reasoning', content: lastStreamedContent.reasoning }, ...lastStreamedContent.parts]
   278→        : lastStreamedContent.parts;
   279→      list = [...list.slice(0, lastUserIdx + 1), { role: 'assistant', parts: filterParts(parts, hideToolsAndThinking) }];
   280→    }
   281→  }
   282→  return list;
   283→}
   284→
   285→export default function ChatWindow({
   286→  headerTitle,
   287→  conversation,
   288→  providers,
   289→  bots,
   290→  sending,
   291→  streaming,
   292→  lastStreamedContent,
   293→  inputDraft,
   294→  onInputDraftChange,
   295→  onSend,
   296→  onUpdateProvider,
   297→  onUpdateBot,
   298→  pendingApprovals,
   299→  onApproveTool,
   300→  onRejectTool,
   301→}: ChatWindowProps) {
   302→  const [hideToolsAndThinking, setHideToolsAndThinking] = useState(false);
   303→  const [isRecording, setIsRecording] = useState(false);
   304→  const [speakingIdx, setSpeakingIdx] = useState<number | null>(null);
   305→  const messagesRef = useRef<HTMLDivElement>(null);
   306→  const topRef = useRef<HTMLDivElement>(null);
   307→  const bottomRef = useRef<HTMLDivElement>(null);
   308→  const recognitionRef = useRef<any>(null);
   309→
   310→  // Stop recording and TTS when conversation changes
   311→  useEffect(() => {
   312→    recognitionRef.current?.stop();
   313→    setIsRecording(false);
   314→    speechSynthesis.cancel();
   315→    setSpeakingIdx(null);
   316→  }, [conversation?.id]);
   317→
   318→  const visibleMessages = conversation
   319→    ? getDisplayMessages(conversation.messages, hideToolsAndThinking, lastStreamedContent)
   320→    : [];
   321→
   322→  useEffect(() => {
   323→    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
   324→  }, [conversation?.messages.length, streaming?.reasoning, streaming?.parts?.length]);
   325→
   326→  const hasProvider = Boolean(conversation?.providerId);
   327→  const isDirectChat = Boolean(
   328→    conversation?.participant1 != null && conversation?.participant2 != null
   329→  );
   330→
   331→  const handleSend = () => {
   332→    const trimmed = inputDraft.trim();
   333→    if (!trimmed || sending || !hasProvider) return;
   334→    onSend(trimmed);
   335→  };
   336→
   337→  const scrollToTop = () => topRef.current?.scrollIntoView({ behavior: 'smooth' });
   338→  const scrollToBottom = () => bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
   339→
   340→  const toggleRecording = () => {
   341→    if (isRecording) {
   342→      recognitionRef.current?.stop();
   343→      setIsRecording(false);
   344→      return;
   345→    }
   346→    const SpeechRecognitionAPI =
   347→      (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
   348→    if (!SpeechRecognitionAPI) {
   349→      alert('Speech recognition is not supported in this browser. Try Chrome or Edge.');
   350→      return;
   351→    }
   352→    const recognition = new SpeechRecognitionAPI();
   353→    recognition.continuous = true;
   354→    recognition.interimResults = true;
   355→    recognition.lang = 'en-US';
   356→    // Capture the base text at recording start; all mutations use this as ground truth
   357→    const startBase = inputDraft;
   358→    let committedText = startBase;
   359→    recognition.onresult = (event: any) => {
   360→      let interim = '';
   361→      for (let i = event.resultIndex; i < event.results.length; i++) {
   362→        const t = event.results[i][0].transcript;
   363→        if (event.results[i].isFinal) {
   364→          committedText += (committedText && !committedText.endsWith(' ') ? ' ' : '') + t.trim();
   365→        } else {
   366→          interim = t;
   367→        }
   368→      }
   369→      if (interim) {
   370→        onInputDraftChange(committedText + (committedText && !committedText.endsWith(' ') ? ' ' : '') + interim + ' […]');
   371→      } else {
   372→        onInputDraftChange(committedText);
   373→      }
   374→    };
   375→    recognition.onend = () => {
   376→      setIsRecording(false);
   377→      onInputDraftChange(committedText);
   378→    };
   379→    recognition.onerror = () => {
   380→      setIsRecording(false);
   381→      onInputDraftChange(committedText);
   382→    };
   383→    recognitionRef.current = recognition;
   384→    recognition.start();
   385→    setIsRecording(true);
   386→  };
   387→
   388→  const speakMessage = (msg: DisplayMessage, idx: number) => {
   389→    if (speakingIdx === idx) {
   390→      speechSynthesis.cancel();
   391→      setSpeakingIdx(null);
   392→      return;
   393→    }
   394→    const text = getMessagePlainText(msg, !hideToolsAndThinking);
   395→    if (!text.trim()) return;
   396→    speechSynthesis.cancel();
   397→    const utterance = new SpeechSynthesisUtterance(text);
   398→    utterance.onend = () => setSpeakingIdx(null);
   399→    utterance.onerror = () => setSpeakingIdx(null);
   400→    setSpeakingIdx(idx);
   401→    speechSynthesis.speak(utterance);
   402→  };
   403→
   404→  if (!conversation) {
   405→    return (
   406→      <main className="flex-1 flex flex-col min-w-0">
   407→        <header className="flex flex-wrap items-center gap-3 py-3.5 px-5 border-b border-border">
   408→          <h2 className="flex-1 min-w-0 text-base font-semibold text-text-bright truncate">{headerTitle}</h2>
   409→        </header>
   410→        <div className="flex-1 flex items-center justify-center text-text-dim text-base">
   411→          <p>
   412→            {headerTitle === 'User'
   413→              ? 'Select or create a conversation to start chatting'
   414→              : `Select or create a conversation with ${headerTitle} to start chatting`}
   415→          </p>
   416→        </div>
   417→      </main>
   418→    );
   419→  }
   420→
   421→  return (
   422→    <main className="flex-1 flex flex-col min-w-0">
   423→      <header className="flex flex-wrap items-center gap-3 py-3.5 px-5 border-b border-border">
   424→        <h2 className="flex-1 min-w-0 text-base font-semibold text-text-bright truncate">{headerTitle}</h2>
   425→        <button
   426→          className={`py-1 px-3 border rounded-lg cursor-pointer text-xs transition-all duration-150 whitespace-nowrap ${
   427→            hideToolsAndThinking
   428→              ? 'bg-bg-active border-accent text-accent'
   429→              : 'bg-bg-input text-text-dim border-border hover:border-accent hover:text-text-bright'
   430→          }`}
   431→          onClick={() => setHideToolsAndThinking((v) => !v)}
   432→          title={hideToolsAndThinking ? 'Show tools and thinking' : 'Hide tools and thinking'}
   433→        >
   434→          {hideToolsAndThinking ? 'Show tools and thinking' : 'Hide tools and thinking'}
   435→        </button>
   436→      </header>
   437→
   438→      <div className="flex-1 overflow-y-auto py-4 px-5 flex flex-col gap-3" ref={messagesRef}>
   439→        <div ref={topRef} />
   440→        {visibleMessages.map((msg, i) => (
   441→          <MessageEntry
   442→            key={i}
   443→            msg={msg}
   444→            conversation={conversation}
   445→            speaking={speakingIdx === i}
   446→            onSpeak={() => speakMessage(msg, i)}
   447→          />
   448→        ))}
   449→        {sending && (() => {
   450→          const assistantLabel = roleDisplayName('assistant', conversation);
   451→          return (
   452→          <div className="max-w-[80%] py-2.5 px-3.5 rounded-lg text-sm leading-relaxed self-start bg-assistant-bg border border-border opacity-95">
   453→            <div className="flex items-baseline gap-2 cursor-pointer select-none">
   454→              <span className={`text-[0.6875rem] font-semibold tracking-wide text-text-dim shrink-0 ${['user', 'assistant', 'tool'].includes(assistantLabel.toLowerCase()) ? 'uppercase' : ''}`}>
   455→                {assistantLabel}
   456→              </span>
   457→            </div>
   458→            <div className="text-text-bright mt-1.5 min-w-0 break-words">
   459→              {streaming?.reasoning ? (
   460→                <details className="mb-2" open>
   461→                  <summary className="cursor-pointer text-text-dim text-xs font-semibold uppercase">
   462→                    Thinking
   463→                  </summary>
   464→                  <pre className="mt-1.5 p-2 bg-bg rounded-lg text-xs text-text-dim whitespace-pre-wrap break-words max-h-[200px] overflow-y-auto">
   465→                    {streaming.reasoning}
   466→                  </pre>
   467→                </details>
   468→              ) : null}
   469→              {streaming?.reasoning && streaming.parts.length > 0 ? (
   470→                <div className="h-px bg-border my-2" />
   471→              ) : null}
   472→              {streaming?.parts.map((part, i) =>
   473→                part.type === 'tool' ? (
   474→                  <details key={i} className="message-tool-part my-2 py-2 px-2.5 bg-tool-bg border border-tool-border rounded-lg text-tool-text max-w-full overflow-hidden" open>
   475→                    <summary className="flex items-center gap-2 cursor-pointer text-xs font-semibold uppercase text-tool-summary list-none [&::-webkit-details-marker]:hidden [&::marker]:hidden">
   476→                      <span>Tool</span>
   477→                      <span className="btn-msg-toggle flex items-center justify-center w-6 h-6 ml-auto shrink-0 rounded-md border border-tool-border bg-tool-bg/80 text-[0.65rem] font-medium leading-none transition-all duration-150 hover:border-tool-summary hover:opacity-90" />
   478→                    </summary>
   479→                    <pre className="mt-1.5 font-mono text-xs text-tool-text whitespace-pre-wrap break-words max-w-full overflow-x-auto overflow-y-hidden">
   480→                      {part.content}
   481→                    </pre>
   482→                  </details>
   483→                ) : (
   484→                  <span key={i} className="whitespace-pre-wrap break-words">{part.content}</span>
   485→                )
   486→              )}
   487→              {streaming && streaming.parts.length === 0 && !streaming.reasoning && (
   488→                <span className="whitespace-pre-wrap break-words">Thinking…</span>
   489→              )}
   490→            </div>
   491→          </div>
   492→          );
   493→        })()}
   494→        {pendingApprovals.map((approval) => (
   495→          <ToolApprovalCard
   496→            key={approval.approvalId}
   497→            approval={approval}
   498→            onApprove={() => onApproveTool(approval.approvalId)}
   499→            onReject={() => onRejectTool(approval.approvalId)}
   500→          />
   501→        ))}
   502→        <div ref={bottomRef} />
   503→      </div>
   504→
   505→      <div className="flex items-end gap-2 py-3 px-5 border-t border-border bg-bg-sidebar">
   506→        <div className="flex flex-col gap-1">
   507→          <button
   508→            className="w-7 h-7 bg-bg-input text-text-dim border border-border rounded-lg cursor-pointer text-[0.7rem] flex items-center justify-center transition-all duration-150 hover:border-accent hover:text-text-bright p-0 disabled:opacity-50 disabled:cursor-not-allowed"
   509→            onClick={scrollToTop}
   510→            title="Scroll to top"
   511→          >
   512→            ▲
   513→          </button>
   514→          <button
   515→            className="w-7 h-7 bg-bg-input text-text-dim border border-border rounded-lg cursor-pointer text-[0.7rem] flex items-center justify-center transition-all duration-150 hover:border-accent hover:text-text-bright p-0"
   516→            onClick={scrollToBottom}
   517→            title="Scroll to bottom"
   518→          >
   519→            ▼
   520→          </button>
   521→        </div>
   522→        <textarea
   523→          value={inputDraft}
   524→          onChange={(e) => onInputDraftChange(e.target.value)}
   525→          onKeyDown={(e) => {
   526→            if (e.key === 'Enter' && !e.shiftKey) {
   527→              e.preventDefault();
   528→              handleSend();
   529→            }
   530→          }}
   531→          placeholder="Type a message… (Enter to send, Shift+Enter for newline)"
   532→          disabled={sending || !hasProvider}
   533→          rows={2}
   534→          className="flex-1 py-2.5 px-3.5 bg-bg-input text-text border border-border rounded-lg font-inherit text-sm resize-none outline-none leading-normal focus:border-accent"
   535→        />
   536→        <button
   537→          className={`w-9 h-9 flex items-center justify-center rounded-lg border cursor-pointer transition-all duration-150 shrink-0 ${
   538→            isRecording
   539→              ? 'bg-danger/20 border-danger text-danger animate-pulse'
   540→              : 'bg-bg-input text-text-dim border-border hover:border-accent hover:text-accent hover:bg-bg-hover'
   541→          } disabled:opacity-40 disabled:cursor-not-allowed`}
   542→          onClick={toggleRecording}
   543→          disabled={sending || !hasProvider}
   544→          title={isRecording ? 'Stop recording' : 'Speak (voice input)'}
   545→        >
   546→          <MicIcon />
   547→        </button>
   548→        <div className="flex flex-col gap-1 items-end shrink-0">
   549→          <select
   550→            value={conversation.providerId ?? ''}
   551→            onChange={(e) => onUpdateProvider(conversation.id, e.target.value || null)}
   552→            className="py-1.5 px-2.5 bg-bg-input text-text border border-border rounded-lg text-[0.8125rem] outline-none focus:border-accent min-w-[140px]"
   553→          >
   554→            <option value="">Select agent…</option>
   555→            {providers.map((p) => (
   556→              <option key={p.id} value={p.id}>{p.name}</option>
   557→            ))}
   558→          </select>
   559→          {!isDirectChat && (
   560→            <select
   561→              value={conversation.botName ?? 'default'}
   562→              onChange={(e) => onUpdateBot(conversation.id, e.target.value === 'default' ? null : e.target.value)}
   563→              className="py-1.5 px-2.5 bg-bg-input text-text border border-border rounded-lg text-[0.8125rem] outline-none focus:border-accent min-w-[140px]"
   564→            >
   565→              <option value="default">default</option>
   566→              {bots.map((b) => (
   567→                <option key={b.name} value={b.name}>{b.name}</option>
   568→              ))}
   569→            </select>
   570→          )}
   571→          {!hasProvider && (
   572→            <span className="text-[0.6875rem] text-text-dim">Select agent to send</span>
   573→          )}
   574→          <button
   575→            className="py-2.5 px-5 bg-accent text-white border-0 rounded-lg cursor-pointer text-sm font-medium transition-colors duration-150 w-full hover:bg-accent-hover disabled:opacity-40 disabled:cursor-not-allowed"
   576→            onClick={handleSend}
   577→            disabled={sending || !hasProvider || !inputDraft.trim()}
   578→          >
   579→            Send
   580→          </button>
   581→        </div>
   582→      </div>
   583→    </main>
   584→  );
   585→}
