    >
      <FileIcon />
      <span className="truncate">{file.name}</span>
      {onRemove && (
        <button
          className="ml-0.5 text-text-dim hover:text-danger text-[0.7rem] leading-none cursor-pointer shrink-0"
          onClick={(e) => { e.stopPropagation(); onRemove(); }}
          title="Remove"
        >
          ✕
        </button>
      )}
    </div>
  );
}

