   294→function parseStructuredContent(content: string): StreamPart[] | null {
   295→  if (!content || typeof content !== 'string') return null;
   296→  const trimmed = content.trim();
   297→  if (!trimmed.startsWith('{"parts":')) return null;
   298→  try {
   299→    const data = JSON.parse(content) as { parts?: Array<{ type: string; content: string }> };
   300→    if (!Array.isArray(data.parts)) return null;
   301→    const parts: StreamPart[] = data.parts
   302→      .filter((p) => p && (p.type === 'answer' || p.type === 'tool' || p.type === 'reasoning') && typeof p.content === 'string')
   303→      .map((p) => ({ type: p.type as 'answer' | 'tool' | 'reasoning', content: p.content }));
   304→    return parts.length > 0 ? parts : null;
   305→  } catch {
   306→    return null;
   307→  }
   308→}
   309→
   310→function filterParts(parts: StreamPart[], hideToolsAndThinking: boolean): StreamPart[] {
   311→  if (!hideToolsAndThinking) return parts;
   312→  const answerParts = parts.filter((p) => p.type === 'answer');
   313→  return answerParts.map((p, i, arr) => ({
   314→    ...p,
   315→    content: p.content + (i < arr.length - 1 ? '\n\n' : ''),
   316→  }));
   317→}
   318→
   319→function getDisplayMessages(
   320→  messages: ChatMessage[],
   321→  hideToolsAndThinking: boolean,
   322→  lastStreamedContent: { reasoning: string; parts: StreamPart[] } | null
   323→): DisplayMessage[] {
   324→  let list: DisplayMessage[] = messages.map((msg) => {
   325→    if (msg.role === 'assistant') {
   326→      const parts = parseStructuredContent(msg.content);
   327→      if (parts) return { role: 'assistant' as const, parts: filterParts(parts, hideToolsAndThinking) };
   328→    }
   329→    return msg;
   330→  });
   331→  if (lastStreamedContent && list.length > 0) {
   332→    const lastUserIdx = Math.max(...list.map((msg, i) => (msg.role === 'user' ? i : -1)));
   333→    const afterLastUser = list.slice(lastUserIdx + 1);
   334→    if (afterLastUser.length === 1 && afterLastUser[0].role === 'assistant') {
   335→      const parts: StreamPart[] = lastStreamedContent.reasoning
   336→        ? [{ type: 'reasoning', content: lastStreamedContent.reasoning }, ...lastStreamedContent.parts]
   337→        : lastStreamedContent.parts;
   338→      list = [...list.slice(0, lastUserIdx + 1), { role: 'assistant', parts: filterParts(parts, hideToolsAndThinking) }];
   339→    }
   340→  }
   341→  return list;
   342→}
