   473→    isInternalChangeRef.current = true;
   474→    onInputDraftChange(editablePlainText(el));
   475→    setHasContent(editableHasContent(el));
   476→  };
   477→
   478→  const handleEditableClick = (e: React.MouseEvent<HTMLDivElement>) => {
   479→    const target = e.target as HTMLElement;
   480→    if (target.dataset.removeChipId) {
   481→      const chip = target.closest('[data-file-id]') as HTMLElement | null;
   482→      chip?.remove();
   483→      isInternalChangeRef.current = true;
   484→      const el = editableRef.current;
   485→      if (el) {
   486→        onInputDraftChange(editablePlainText(el));
   487→        setHasContent(editableHasContent(el));
   488→      }
   489→    }
   490→  };
   491→
   492→  const handleFileSelect = async (e: React.ChangeEvent<HTMLInputElement>) => {
   493→    const files = Array.from(e.target.files ?? []);
   494→    if (files.length === 0) return;
   495→    e.target.value = '';
   496→    setUploadingFile(true);
   497→    try {
   498→      const uploaded = await Promise.all(files.map((f) => api.uploadFile(f)));
   499→      uploaded.forEach(insertFileChip);
   500→    } catch {
   501→      // ignore upload errors silently
   502→    } finally {
   503→      setUploadingFile(false);
   504→    }
   505→  };
   506→
   507→  const insertFileChip = (attachment: FileAttachment) => {
   508→    const el = editableRef.current;
   509→    if (!el) return;
   510→    el.focus();
   511→    const chip = document.createElement('span');
   512→    chip.contentEditable = 'false';
   513→    chip.dataset.fileId = attachment.id;
   514→    chip.dataset.fileName = attachment.name;
   515→    chip.dataset.fileMimeType = attachment.mimeType;
   516→    chip.className = FILE_CHIP_CLASS;
   517→    chip.title = attachment.name;
   518→    chip.innerHTML =
   519→      `<svg width="11" height="11" viewBox="0 0 12 12" fill="none" stroke="currentColor" stroke-width="1.2" stroke-linecap="round" stroke-linejoin="round" style="flex-shrink:0"><path d="M7 1H3a1 1 0 00-1 1v8a1 1 0 001 1h6a1 1 0 001-1V4L7 1z"/><path d="M7 1v3h3"/></svg>` +
   520→      `<span style="max-width:120px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${escapeHtml(attachment.name)}</span>` +
   521→      `<span data-remove-chip-id="${attachment.id}" style="cursor:pointer;margin-left:2px;opacity:0.7;flex-shrink:0" title="Remove">✕</span>`;
   522→
   523→    const sel = window.getSelection();
   524→    if (sel && sel.rangeCount > 0 && el.contains(sel.getRangeAt(0).commonAncestorContainer)) {
   525→      const range = sel.getRangeAt(0);
   526→      range.deleteContents();
   527→      range.insertNode(chip);
   528→      range.setStartAfter(chip);
   529→      range.collapse(true);
   530→      sel.removeAllRanges();
   531→      sel.addRange(range);
   532→    } else {
   533→      el.appendChild(chip);
   534→    }
   535→    // Ensure a text node follows so typing continues naturally
   536→    const space = document.createTextNode('\u00A0');
   537→    chip.after(space);
   538→    const r = document.createRange();
   539→    r.setStart(space, 1);
   540→    r.collapse(true);
   541→    const s = window.getSelection();
   542→    s?.removeAllRanges();
   543→    s?.addRange(r);
   544→
   545→    isInternalChangeRef.current = true;
   546→    onInputDraftChange(editablePlainText(el));
   547→    setHasContent(true);
   548→  };
   549→
   550→  const scrollToTop = () => topRef.current?.scrollIntoView({ behavior: 'smooth' });
   551→  const scrollToBottom = () => bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
   552→
   553→  const toggleRecording = () => {
   554→    if (isRecording) {
   555→      recognitionRef.current?.stop();
   556→      setIsRecording(false);
   557→      return;
   558→    }
   559→    const SpeechRecognitionAPI =
   560→      (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
   561→    if (!SpeechRecognitionAPI) {
   562→      alert('Speech recognition is not supported in this browser. Try Chrome or Edge.');
   563→      return;
   564→    }
   565→    const recognition = new SpeechRecognitionAPI();
   566→    recognition.continuous = true;
   567→    recognition.interimResults = true;
   568→    recognition.lang = 'en-US';
   569→    // Capture the base text at recording start; all mutations use this as ground truth
   570→    const startBase = editableRef.current ? editablePlainText(editableRef.current) : inputDraft;
   571→    let committedText = startBase;
   572→    recognition.onresult = (event: any) => {
   573→      let interim = '';
   574→      for (let i = event.resultIndex; i < event.results.length; i++) {
   575→        const t = event.results[i][0].transcript;
   576→        if (event.results[i].isFinal) {
   577→          committedText += (committedText && !committedText.endsWith(' ') ? ' ' : '') + t.trim();
   578→        } else {
   579→          interim = t;
   580→        }
   581→      }
   582→      if (interim) {
   583→        onInputDraftChange(committedText + (committedText && !committedText.endsWith(' ') ? ' ' : '') + interim + ' […]');
   584→      } else {
   585→        onInputDraftChange(committedText);
   586→      }
   587→    };
   588→    recognition.onend = () => {
   589→      setIsRecording(false);
   590→      onInputDraftChange(committedText);
   591→    };
   592→    recognition.onerror = () => {
   593→      setIsRecording(false);
   594→      onInputDraftChange(committedText);
   595→    };
   596→    recognitionRef.current = recognition;
   597→    recognition.start();
   598→    setIsRecording(true);
   599→  };
   600→
   601→  const speakMessage = (msg: DisplayMessage, idx: number) => {
   602→    if (speakingIdx === idx) {
   603→      speechSynthesis.cancel();
   604→      setSpeakingIdx(null);
   605→      return;
   606→    }
   607→    const text = getMessagePlainText(msg, !hideToolsAndThinking);
   608→    if (!text.trim()) return;
   609→    speechSynthesis.cancel();
   610→    const utterance = new SpeechSynthesisUtterance(text);
   611→    utterance.onend = () => setSpeakingIdx(null);
   612→    utterance.onerror = () => setSpeakingIdx(null);
   613→    setSpeakingIdx(idx);
   614→    speechSynthesis.speak(utterance);
   615→  };
   616→
   617→  if (!conversation) {
   618→    return (
   619→      <main className="flex-1 flex flex-col min-w-0">
   620→        <header className="flex flex-wrap items-center gap-3 py-3.5 px-5 border-b border-border">
   621→          <h2 className="flex-1 min-w-0 text-base font-semibold text-text-bright truncate">{headerTitle}</h2>
   622→        </header>
   623→        <div className="flex-1 flex items-center justify-center text-text-dim text-base">
   624→          <p>
   625→            {headerTitle === 'User'
   626→              ? 'Select or create a conversation to start chatting'
   627→              : `Select or create a conversation with ${headerTitle} to start chatting`}
   628→          </p>
   629→        </div>
   630→      </main>
   631→    );
   632→  }
   633→
   634→  return (
   635→    <main className="flex-1 flex flex-col min-w-0">
   636→      <header className="flex flex-wrap items-center gap-3 py-3.5 px-5 border-b border-border">
   637→        <h2 className="flex-1 min-w-0 text-base font-semibold text-text-bright truncate">{headerTitle}</h2>
   638→        <button
   639→          className={`py-1 px-3 border rounded-lg cursor-pointer text-xs transition-all duration-150 whitespace-nowrap ${
   640→            hideToolsAndThinking
   641→              ? 'bg-bg-active border-accent text-accent'
   642→              : 'bg-bg-input text-text-dim border-border hover:border-accent hover:text-text-bright'
   643→          }`}
   644→          onClick={() => setHideToolsAndThinking((v) => !v)}
   645→          title={hideToolsAndThinking ? 'Show tools and thinking' : 'Hide tools and thinking'}
   646→        >
   647→          {hideToolsAndThinking ? 'Show tools and thinking' : 'Hide tools and thinking'}
   648→        </button>
   649→      </header>
   650→
   651→      <div className="flex-1 overflow-y-auto py-4 px-5 flex flex-col gap-3" ref={messagesRef}>
   652→        <div ref={topRef} />
   653→        {visibleMessages.map((msg, i) => (
   654→          <MessageEntry
   655→            key={i}
   656→            msg={msg}
   657→            conversation={conversation}
   658→            speaking={speakingIdx === i}
   659→            onSpeak={() => speakMessage(msg, i)}
   660→          />
   661→        ))}
   662→        {sending && (() => {
   663→          const assistantLabel = roleDisplayName('assistant', conversation);
   664→          return (
   665→          <div className="max-w-[80%] py-2.5 px-3.5 rounded-lg text-sm leading-relaxed self-start bg-assistant-bg border border-border opacity-95">
   666→            <div className="flex items-baseline gap-2 cursor-pointer select-none">
   667→              <span className={`text-[0.6875rem] font-semibold tracking-wide text-text-dim shrink-0 ${['user', 'assistant', 'tool'].includes(assistantLabel.toLowerCase()) ? 'uppercase' : ''}`}>
   668→                {assistantLabel}
   669→              </span>
   670→            </div>
   671→            <div className="text-text-bright mt-1.5 min-w-0 break-words">
   672→              {streaming?.reasoning ? (
   673→                <details className="mb-2" open>
   674→                  <summary className="cursor-pointer text-text-dim text-xs font-semibold uppercase">
   675→                    Thinking
   676→                  </summary>
   677→                  <pre className="mt-1.5 p-2 bg-bg rounded-lg text-xs text-text-dim whitespace-pre-wrap break-words max-h-[200px] overflow-y-auto">
   678→                    {streaming.reasoning}
   679→                  </pre>
   680→                </details>
   681→              ) : null}
   682→              {streaming?.reasoning && streaming.parts.length > 0 ? (
   683→                <div className="h-px bg-border my-2" />
   684→              ) : null}
   685→              {streaming?.parts.map((part, i) =>
   686→                part.type === 'tool' ? (
   687→                  <details key={i} className="message-tool-part my-2 py-2 px-2.5 bg-tool-bg border border-tool-border rounded-lg text-tool-text max-w-full overflow-hidden" open>
   688→                    <summary className="flex items-center gap-2 cursor-pointer text-xs font-semibold uppercase text-tool-summary list-none [&::-webkit-details-marker]:hidden [&::marker]:hidden">
   689→                      <span>Tool</span>
   690→                      <span className="btn-msg-toggle flex items-center justify-center w-6 h-6 ml-auto shrink-0 rounded-md border border-tool-border bg-tool-bg/80 text-[0.65rem] font-medium leading-none transition-all duration-150 hover:border-tool-summary hover:opacity-90" />
   691→                    </summary>
   692→                    <pre className="mt-1.5 font-mono text-xs text-tool-text whitespace-pre-wrap break-words max-w-full overflow-x-auto overflow-y-hidden">
   693→                      {part.content}
   694→                    </pre>
   695→                  </details>
   696→                ) : (
   697→                  <span key={i} className="whitespace-pre-wrap break-words">{part.content}</span>
   698→                )
   699→              )}
   700→              {streaming && streaming.parts.length === 0 && !streaming.reasoning && (
   701→                <span className="whitespace-pre-wrap break-words">Thinking…</span>
   702→              )}
   703→            </div>
   704→          </div>
   705→          );
   706→        })()}
   707→        {pendingApprovals.map((approval) => (
   708→          <ToolApprovalCard
   709→            key={approval.approvalId}
   710→            approval={approval}
   711→            onApprove={() => onApproveTool(approval.approvalId)}
   712→            onReject={() => onRejectTool(approval.approvalId)}
   713→          />
   714→        ))}
   715→        <div ref={bottomRef} />
   716→      </div>
   717→
   718→      <div className="flex items-end gap-2 py-3 px-5 border-t border-border bg-bg-sidebar">
   719→        <div className="flex flex-col gap-1">
   720→          <button
   721→            className="w-7 h-7 bg-bg-input text-text-dim border border-border rounded-lg cursor-pointer text-[0.7rem] flex items-center justify-center transition-all duration-150 hover:border-accent hover:text-text-bright p-0 disabled:opacity-50 disabled:cursor-not-allowed"
   722→            onClick={scrollToTop}
   723→            title="Scroll to top"
   724→          >
   725→            ▲
   726→          </button>
   727→          <button
   728→            className="w-7 h-7 bg-bg-input text-text-dim border border-border rounded-lg cursor-pointer text-[0.7rem] flex items-center justify-center transition-all duration-150 hover:border-accent hover:text-text-bright p-0"
   729→            onClick={scrollToBottom}
   730→            title="Scroll to bottom"
   731→          >
   732→            ▼
   733→          </button>
   734→        </div>
   735→        <div
   736→          ref={editableRef}
   737→          contentEditable={sending || !hasProvider ? 'false' : 'true'}
   738→          suppressContentEditableWarning
   739→          onInput={handleEditableInput}
   740→          onClick={handleEditableClick}
   741→          onKeyDown={(e) => {
   742→            if (e.key === 'Enter' && !e.shiftKey) {
   743→              e.preventDefault();
   744→              handleSend();
   745→            }
   746→          }}
   747→          data-placeholder="Type a message… (Enter to send, Shift+Enter for newline)"
   748→          className={`flex-1 min-h-[3rem] max-h-40 overflow-y-auto py-2.5 px-3.5 bg-bg-input text-text border border-border rounded-lg text-sm leading-normal outline-none focus:border-accent empty:before:content-[attr(data-placeholder)] empty:before:text-text-dim ${sending || !hasProvider ? 'opacity-50 cursor-not-allowed' : ''}`}
   749→        />
   750→        <input
   751→          ref={fileInputRef}
   752→          type="file"
   753→          multiple
   754→          className="hidden"
   755→          onChange={handleFileSelect}
   756→        />
   757→        <button
   758→          className={`w-9 h-9 flex items-center justify-center rounded-lg border cursor-pointer transition-all duration-150 shrink-0 ${
   759→            isRecording
   760→              ? 'bg-danger/20 border-danger text-danger animate-pulse'
   761→              : 'bg-bg-input text-text-dim border-border hover:border-accent hover:text-accent hover:bg-bg-hover'
   762→          } disabled:opacity-40 disabled:cursor-not-allowed`}
   763→          onClick={toggleRecording}
   764→          disabled={sending || !hasProvider}
   765→          title={isRecording ? 'Stop recording' : 'Speak (voice input)'}
   766→        >
   767→          <MicIcon />
   768→        </button>
   769→        <button
   770→          className="w-9 h-9 flex items-center justify-center rounded-lg border cursor-pointer transition-all duration-150 shrink-0 bg-bg-input text-text-dim border-border hover:border-accent hover:text-accent hover:bg-bg-hover disabled:opacity-40 disabled:cursor-not-allowed"
   771→          onClick={() => fileInputRef.current?.click()}
   772→          disabled={sending || !hasProvider || uploadingFile}
   773→          title="Attach files"
   774→        >
   775→          <PaperclipIcon />
   776→        </button>
   777→        <div className="flex flex-col gap-1 items-end shrink-0">
   778→          <select
   779→            value={conversation.providerId ?? ''}
   780→            onChange={(e) => onUpdateProvider(conversation.id, e.target.value || null)}
   781→            className="py-1.5 px-2.5 bg-bg-input text-text border border-border rounded-lg text-[0.8125rem] outline-none focus:border-accent min-w-[140px]"
   782→          >
   783→            <option value="">Select agent…</option>
   784→            {providers.map((p) => (
   785→              <option key={p.id} value={p.id}>{p.name}</option>
   786→            ))}
   787→          </select>
   788→          {!isDirectChat && (
   789→            <select
   790→              value={conversation.botName ?? 'default'}
   791→              onChange={(e) => onUpdateBot(conversation.id, e.target.value === 'default' ? null : e.target.value)}
   792→              className="py-1.5 px-2.5 bg-bg-input text-text border border-border rounded-lg text-[0.8125rem] outline-none focus:border-accent min-w-[140px]"
   793→            >
   794→              <option value="default">default</option>
   795→              {bots.map((b) => (
   796→                <option key={b.name} value={b.name}>{b.name}</option>
   797→              ))}
   798→            </select>
   799→          )}
   800→          {!hasProvider && (
   801→            <span className="text-[0.6875rem] text-text-dim">Select agent to send</span>
   802→          )}
   803→          <button
   804→            className="py-2.5 px-5 bg-accent text-white border-0 rounded-lg cursor-pointer text-sm font-medium transition-colors duration-150 w-full hover:bg-accent-hover disabled:opacity-40 disabled:cursor-not-allowed"
   805→            onClick={handleSend}
   806→            disabled={sending || !hasProvider || !hasContent}
   807→          >
   808→            Send
   809→          </button>
